  <div id="app">
    <!-- 启动引导页（第一屏） -->
    <div class="intro-page" v-if="showSplash">
      <!-- 背景装饰层 -->
      <div class="bg-decoration">
        <div class="olive-pattern pattern-1"></div>
        <div class="olive-pattern pattern-2"></div>
