        <div class="timer-animation">
          <span class="timer-number">{{ displayNumber }}</span>
          <span class="timer-unit">秒</span>
        </div>

        <!-- 标题区域 -->
        <div class="title-section">
          <h1 class="main-title">
            <span class="title-line">增城榄雕非遗</span>
            <span class="title-line highlight">"活态传承"</span>
            <span class="title-line">与Z世代的双向奔赴</span>
          </h1>
          <p class="subtitle">探索传统工艺与年轻一代的创新碰撞</p>
        </div>

        <!-- 开始探索按钮 -->
        <button class="explore-btn" @click="startExplore">
          <span class="btn-text">开始探索</span>
          <div class="btn-border"></div>
          <div class="btn-glow"></div>
        </button>
      </div>
    </div>

    <!-- 路由内容（点击开始探索后显示） -->
    <router-view v-else />
  </div>
</template>

<script>
export default {
  name: 'App',
  data () {
    return {
      showSplash: true,
      displayNumber: 30,
      timer: null
    }
  },
  mounted () {
    // 30秒倒计时动画
    this.timer = setInterval(() => {
      this.displayNumber--
      if (this.displayNumber <= 0) {
        this.displayNumber = 30
      }
    }, 1000)
  },
  beforeDestroy () {
    clearInterval(this.timer)
  },
  methods: {
    startExplore () {
      this.showSplash = false
      this.$router.push('/background').catch(err => {
        if (err.name !== 'NavigationDuplicated') throw err
      })
    }
  }
}
</script>

