import Vue from 'vue'
import VueRouter from 'vue-router'

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: () => import('../views/H5Container.vue'),
    redirect: '/background',
    children: [
      {
        path: 'intro',
        name: 'Intro',
        component: () => import('../views/pages/IntroPage.vue'),
        meta: { title: '开篇引导', index: 0 }
      },
      {
        path: 'background',
        name: 'Background',
        component: () => import('../views/pages/BackgroundPage.vue'),
        meta: { title: '非遗基础认知', index: 1 }
      },
      {
        path: 'data-visualization',
        name: 'DataVisualization',
        component: () => import('../views/pages/DataVisualizationPage.vue'),
        meta: { title: '核心数据可视化', index: 2 }
      },
      {
        path: 'reality-gap',
        name: 'RealityGap',
        component: () => import('../views/pages/RealityGapPage.vue'),
        meta: { title: '现实反差探究', index: 3 }
      },
      {
        path: 'inheritance-path',
        name: 'InheritancePath',
        component: () => import('../views/pages/InheritancePathPage.vue'),
        meta: { title: '传承路径分析', index: 4 }
      },
      {
        path: 'breakout-plans',
        name: 'BreakoutPlans',
        component: () => import('../views/pages/BreakoutPlansPage.vue'),
        meta: { title: '四大破圈方案', index: 5 }
      },
      {
        path: 'interaction',
        name: 'Interaction',
        component: () => import('../views/pages/InteractionPage.vue'),
        meta: { title: '互动参与', index: 6 }
      },
      {
        path: 'ending',
        name: 'Ending',
        component: () => import('../views/pages/EndingPage.vue'),
        meta: { title: '结尾升华', index: 7 }
      }
    ]
  }
]

const router = new VueRouter({
  mode: 'hash',
  base: process.env.BASE_URL,
  routes,
  scrollBehavior(to, from, savedPosition) {
    if (savedPosition) {
      return savedPosition
    } else {
      return { x: 0, y: 0 }
    }
  }
})

export default router
